class Solution:
    def stringCount(self, n):
        MOD = 10 ** 9 + 7

        def p(base, e):
            return pow(base, e, MOD)

        nm1 = n - 1 if n >= 1 else 0
        part1 = (3 * p(25, n) + n * p(25, nm1)) % MOD
        part2 = (3 * p(24, n) + 2 * n * p(24, nm1)) % MOD
        part3 = (p(23, n) + n * p(23, nm1)) % MOD
        union = (part1 - part2 + part3) % MOD
        ans = (p(26, n) - union) % MOD
        return ans % MOD

