var stringCount = function(n) {
    const MOD = 1000000007n;
    const N = BigInt(n);
    function modpow(base, exp) {
        base = base % MOD;
        let result = 1n;
        while (exp > 0n) {
            if (exp & 1n) result = (result * base) % MOD;
            base = (base * base) % MOD;
            exp >>= 1n;
        }
        return result;
    }
    const Nm1 = N > 0n ? N - 1n : 0n;
    const p25n = modpow(25n, N), p25n1 = modpow(25n, Nm1);
    const p24n = modpow(24n, N), p24n1 = modpow(24n, Nm1);
    const p23n = modpow(23n, N), p23n1 = modpow(23n, Nm1);
    const p26n = modpow(26n, N);
    const part1 = ((3n * p25n) % MOD + (N * p25n1) % MOD) % MOD;
    const part2 = ((3n * p24n) % MOD + (2n * N % MOD * p24n1) % MOD) % MOD;
    const part3 = (p23n + (N * p23n1) % MOD) % MOD;
    let union = ((part1 - part2 + part3) % MOD + MOD) % MOD;
    let ans = ((p26n - union) % MOD + MOD) % MOD;
    return Number(ans);
};
